// Parse Islamic calendar and detect special occasions
const hijriData = $('Fetch Hijri Date & Islamic Calendar').item.json.data || {};
const calendarData = $('Fetch Prayer Times & Special Days').item.json.data || [];

const hijriDate = hijriData.hijri || {};
const currentDay = hijriDate.day;
const currentMonth = hijriDate.month?.en || '';
const currentYear = hijriDate.year;

// Detect special Islamic occasions
let specialOccasion = null;
let contentBoost = 1; // Multiplier for content output
let contentTheme = 'general';

// Ramadan detection
if (currentMonth === 'Ramadan' || currentMonth === 'Ramaḍān') {
  specialOccasion = 'ramadan';
  contentBoost = 3; // Triple content during Ramadan
  contentTheme = 'ramadan_productivity';
}

// Eid detection
if (currentMonth === 'Shawwāl' && currentDay <= 3) {
  specialOccasion = 'eid_fitr';
  contentBoost = 2;
  contentTheme = 'eid_celebration';
}
if (currentMonth === 'Dhu al-Ḥijjah' && currentDay >= 10 && currentDay <= 13) {
  specialOccasion = 'eid_adha';
  contentBoost = 2;
  contentTheme = 'eid_qurbani';
}

// Dhul Hijjah (Hajj season)
if (currentMonth === 'Dhu al-Ḥijjah' && currentDay <= 10) {
  specialOccasion = 'hajj_season';
  contentBoost = 2;
  contentTheme = 'hajj_umrah';
}

// Muharram (Islamic New Year)
if (currentMonth === 'Muḥarram' && currentDay <= 10) {
  specialOccasion = 'muharram';
  contentTheme = 'islamic_new_year';
}

// Rabi al-Awwal (Mawlid)
if (currentMonth === 'Rabīʿ al-Awwal' && currentDay === 12) {
  specialOccasion = 'mawlid';
  contentTheme = 'prophetic_teachings';
}

// Jumua (Friday) - always boost Islamic content
const isJumua = new Date().getDay() === 5;
if (isJumua) {
  contentBoost = Math.max(contentBoost, 1.5);
}

return [{
  json: {
    hijri_date: `${currentDay} ${currentMonth} ${currentYear}`,
    gregorian_date: new Date().toISOString().split('T')[0],
    special_occasion: specialOccasion,
    content_boost_multiplier: contentBoost,
    content_theme: contentTheme,
    is_jumua: isJumua,
    is_ramadan: currentMonth.includes('Rama'),
    is_hajj_season: currentMonth === 'Dhu al-Ḥijjah',
    prayer_times: calendarData[parseInt(new Date().getDate()) - 1]?.timings || {},
    recommendations: {
      post_islamic_content: true,
      priority_languages: specialOccasion ? ['ar', 'ur', 'en', 'ms', 'id'] : ['en', 'ur', 'ar'],
      suggested_topics: []
    }
  }
}];

// Parse Islamic content ideas
const raw = $input.first().json.response || '';
const calendarContext = $('Analyze Islamic Calendar Context').item.json;

let ideas;
try {
  const match = raw.match(/```json\n([\s\S]*?)\n```/) || raw.match(/(\{[\s\S]*\})/);
  ideas = JSON.parse(match ? (match[1] || match[0]) : raw);
} catch(e) {
  ideas = {
    content_strategy: 'Generate general Islamic content',
    content_ideas: [{
      title: 'How to Start a Halal Business',
      pillar: 'Halal Business',
      target_keyword: 'halal business ideas',
      target_audience: 'Muslim entrepreneurs',
      languages_priority: ['en', 'ur', 'ar']
    }],
    parse_error: e.message
  };
}

return ideas.content_ideas.map((idea, idx) => ({
  json: {
    ...idea,
    hijri_date: calendarContext.hijri_date,
    special_occasion: calendarContext.special_occasion,
    is_ramadan: calendarContext.is_ramadan,
    is_jumua: calendarContext.is_jumua,
    priority_score: (calendarContext.content_boost_multiplier * 10) + (10 - idx),
    generated_at: new Date().toISOString(),
    content_type: 'islamic',
    halal_verified: true
  }
}));

